class Solution:
    def earliestAndLatest(self, n, firstPlayer, secondPlayer):
        # Independent brute force: actually simulate every bracket outcome.
        # Capped to small n to stay fast; fall back to the recurrence above that size.
        if n > 14:
            return self._rec(n, firstPlayer, secondPlayer)
        from itertools import product
        target = {firstPlayer, secondPlayer}
        best = [99, 0]

        def play(row, rnd):
            m = len(row)
            i, j = 0, m - 1
            while i < j:
                if {row[i], row[j]} == target:
                    if rnd < best[0]:
                        best[0] = rnd
                    if rnd > best[1]:
                        best[1] = rnd
                    return
                i += 1
                j -= 1
            i, j = 0, m - 1
            pairs = []
            mid = None
            while i < j:
                pairs.append((row[i], row[j]))
                i += 1
                j -= 1
            if i == j:
                mid = row[i]
            choices = []
            for a, b in pairs:
                if a in target:
                    choices.append((a,))
                elif b in target:
                    choices.append((b,))
                else:
                    choices.append((a, b))
            for combo in product(*choices):
                winners = list(combo)
                if mid is not None:
                    winners.append(mid)
                winners.sort()
                play(winners, rnd + 1)

        play(list(range(1, n + 1)), 1)
        return [best[0], best[1]]

    def _rec(self, n, firstPlayer, secondPlayer):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(num, f, s):
            if f + s == num + 1:
                return (1, 1)
            if f - 1 > num - s:
                return solve(num, num + 1 - s, num + 1 - f)
            half = (num + 1) // 2
            lo, hi = f + 1, s - 1
            internal = outside = 0
            for p in range(lo, hi + 1):
                q = num + 1 - p
                if q == f or q == s:
                    continue
                if lo <= q <= hi:
                    if p < q:
                        internal += 1
                else:
                    outside += 1
            glo, ghi = internal, internal + outside
            if num % 2 == 1:
                mid = (num + 1) // 2
                if lo <= mid <= hi:
                    glo += 1
                    ghi += 1
            ear, lat = 1 << 30, 0
            for i in range(f):
                fn = i + 1
                for g in range(glo, ghi + 1):
                    sn = fn + g + 1
                    if fn < sn <= half:
                        a, b = solve(half, fn, sn)
                        if a < ear:
                            ear = a
                        if b > lat:
                            lat = b
            return (ear + 1, lat + 1)
        r = solve(n, firstPlayer, secondPlayer)
        return [r[0], r[1]]

