var earliestAndLatest = function(n, firstPlayer, secondPlayer) {
    const memo = new Map();
    const solve = (num, f, s) => {
        if (f + s === num + 1) return [1, 1];
        if (f - 1 > num - s) return solve(num, num + 1 - s, num + 1 - f);
        const key = num + ',' + f + ',' + s;
        const cached = memo.get(key);
        if (cached) return cached;
        const half = (num + 1) >> 1;
        const lo = f + 1, hi = s - 1;
        let internal = 0, outside = 0;
        for (let p = lo; p <= hi; p++) {
            const q = num + 1 - p;
            if (q === f || q === s) continue;
            if (q >= lo && q <= hi) {
                if (p < q) internal++;
            } else {
                outside++;
            }
        }
        let glo = internal, ghi = internal + outside;
        if (num % 2 === 1) {
            const mid = (num + 1) >> 1;
            if (mid >= lo && mid <= hi) { glo++; ghi++; }
        }
        let ear = Infinity, lat = 0;
        for (let i = 0; i < f; i++) {
            const fn = i + 1;
            for (let g = glo; g <= ghi; g++) {
                const sn = fn + g + 1;
                if (fn < sn && sn <= half) {
                    const [a, b] = solve(half, fn, sn);
                    if (a < ear) ear = a;
                    if (b > lat) lat = b;
                }
            }
        }
        const ans = [ear + 1, lat + 1];
        memo.set(key, ans);
        return ans;
    };
    const r = solve(n, firstPlayer, secondPlayer);
    return [r[0], r[1]];
};
